import type { AuthUser } from "@workspace/api-client";
import type { AuthLoginPayload } from "./auth-api";

export type StoreSessionPayload = {
  id: string;
  username: string;
  role: "admin" | "store";
  displayName: string;
};

const AUTH_STORAGE_KEY = "storesync_session";

type SessionSource = AuthUser | AuthLoginPayload;

function isStaffRole(role: { name?: string }) {
  const value = (role.name ?? "").trim().toLowerCase();
  return ["super_admin", "admin", "editor", "manager"].includes(value);
}

export function toStoreSession(user: SessionSource): StoreSessionPayload {
  const hasAdminRole = user.roles.some((role) => isStaffRole(role));
  const displayName =
    user.name?.trim() ||
    user.roles[0]?.displayName ||
    user.roles[0]?.name ||
    user.email ||
    "Người dùng HUB";

  return {
    id: String(user.id),
    username: user.email,
    role: hasAdminRole ? "admin" : "store",
    displayName,
  };
}

export function persistSession(session: StoreSessionPayload) {
  window.localStorage.setItem(AUTH_STORAGE_KEY, JSON.stringify(session));
  window.dispatchEvent(new Event("storesync-session"));
}

src/features/auth/sign-in-form.tsx.content:
"use client";

import { useEffect, useRef, useState } from "react";
import { useRouter } from "next/navigation";
import Link from "next/link";
import { toast } from "sonner";
import { Eye, EyeOff } from "lucide-react";
import { canAccessStaffAdmin, type AuthUser } from "@workspace/api-client";
import { Button } from "@ui/components/button";
import { Card, CardContent } from "@ui/components/card";
import {
  Field,
  FieldDescription,
  FieldError,
  FieldGroup,
  FieldLabel,
  FieldSeparator,
} from "@ui/components/field";
import { Input } from "@ui/components/input";
import { PointerHighlight } from "@ui/components/pointer-highlight";
import { TypographyH2 } from "@ui/components/typography";
import {
  Select,
  SelectContent,
  SelectItem,
  SelectTrigger,
  SelectValue,
} from "@ui/components/select";
import { useAuth, useClientReady } from "@/providers/auth-provider";
import { fetchDevLoginOptions, type DevLoginOption } from "@/features/auth/auth-api";
import {
  AUTH_LOGIN_PATH,
  AUTH_REGISTER_PATH,
} from "@/lib/auth-routes";
import {
  ADMIN_SESSION_EVENT,
  writeAdminSession,
} from "@/lib/auth-session";

function decodeBridgeSession(raw: string): AuthUser | null {
  try {
    const binary = window.atob(raw);
    const bytes = Uint8Array.from(binary, (char) => char.charCodeAt(0));
    const json = new TextDecoder().decode(bytes);
    const user = JSON.parse(json) as AuthUser;

    if (
      typeof user?.id !== "string" ||
      typeof user?.email !== "string" ||
      !(
        typeof user?.name === "string" ||
        user?.name === null ||
        user?.name === undefined
      ) ||
      !Array.isArray(user?.roles) ||
      !Array.isArray(user?.permissions)
    ) {
      return null;
    }

    return user;
  } catch {
    return null;
  }
}

export function SignInForm() {
  const router = useRouter();
  const { login, loginDevelopment } = useAuth();
  const clientReady = useClientReady();
  const isDevelopment = process.env.NODE_ENV === "development";
  const [email, setEmail] = useState("");
  const [password, setPassword] = useState("");
  const [showPassword, setShowPassword] = useState(false);
  const [error, setError] = useState<string | null>(null);
  const [busy, setBusy] = useState(false);
  const [devLoginOptions, setDevLoginOptions] = useState<DevLoginOption[]>([]);
  const [selectedDevLoginId, setSelectedDevLoginId] = useState("");
  const [devLoginOptionsLoading, setDevLoginOptionsLoading] = useState(false);
  const staffOnlyToastRef = useRef(false);
  const bridgeHandledRef = useRef(false);

  useEffect(() => {
    if (!clientReady || bridgeHandledRef.current) return;
    if (typeof window === "undefined") return;

    const hash = window.location.hash.startsWith("#")
      ? window.location.hash.slice(1)
      : window.location.hash;
    if (!hash) return;

    const params = new URLSearchParams(hash);
    const encodedSession = params.get("session");
    if (!encodedSession) return;

    bridgeHandledRef.current = true;
    const user = decodeBridgeSession(encodedSession);

    if (!user || !canAccessStaffAdmin(user)) {
      toast.error("Không thể đồng bộ phiên đăng nhập quản trị.");
      router.replace(AUTH_LOGIN_PATH);
      return;
    }

    writeAdminSession(user);
    window.dispatchEvent(new Event(ADMIN_SESSION_EVENT));
    toast.success("Đã chuyển sang cổng quản trị.");
    router.replace("/");
  }, [clientReady, router]);

  useEffect(() => {
    if (!clientReady || staffOnlyToastRef.current) return;
    if (typeof window === "undefined") return;
    const q = new URLSearchParams(window.location.search);
    if (q.get("reason") !== "staff_only") return;
    staffOnlyToastRef.current = true;
    toast.error(
      "Tài khoản khách / đại lý không dùng được cổng quản trị. Hãy đăng nhập trên cửa hàng để đặt hàng.",
    );
    router.replace(AUTH_LOGIN_PATH);
  }, [clientReady, router]);

  useEffect(() => {
    if (!clientReady || !isDevelopment) return;

    let cancelled = false;
    setDevLoginOptionsLoading(true);

    void fetchDevLoginOptions()
      .then((options) => {
        if (cancelled) return;
        setDevLoginOptions(options);
      })
      .finally(() => {
        if (cancelled) return;
        setDevLoginOptionsLoading(false);
      });

    return () => {
      cancelled = true;
    };
  }, [clientReady, isDevelopment]);

  const onSelectDevLogin = (value: string | null) => {
    const nextValue = value ?? "";
    setSelectedDevLoginId(nextValue);
    if (!nextValue) return;
    const picked = devLoginOptions.find((option) => option.id === nextValue);
    if (!picked) return;
    setEmail(picked.email);
    setPassword("");
    setError(null);
  };

  const runLogin = async (nextEmail: string, nextPassword: string) => {
    setError(null);
    setBusy(true);
    try {
      const result = await login(nextEmail, nextPassword);
      if (result === "invalid_credentials") {
        const message = "Sai email hoặc mật khẩu.";
        setError(message);
        toast.error(message);
        return;
      }
      if (result === "staff_only") {
        const message =
          "Tài khoản này chỉ dùng trên cửa hàng (khách/đại lý). Cổng quản trị cần tài khoản nội bộ.";
        setError(message);
        toast.error(message);
        return;
      }
      toast.success("Đăng nhập thành công.");
      router.replace("/");
    } finally {
      setBusy(false);
    }
  };

  const onSubmit = async (event: React.FormEvent) => {
    event.preventDefault();
    if (isDevelopment && selectedDevLoginId) {
      setError(null);
      setBusy(true);
      try {
        const result = await loginDevelopment(selectedDevLoginId);
        if (result === "invalid_credentials") {
          const message = "Không thể đăng nhập bằng tài khoản development đã chọn.";
          setError(message);
          toast.error(message);
          return;
        }
        if (result === "staff_only") {
          const message =
            "Tài khoản development này không có quyền dùng cổng quản trị.";
          setError(message);
          toast.error(message);
          return;
        }
        toast.success("Đăng nhập development thành công.");
        router.replace("/");
      } finally {
        setBusy(false);
      }
      return;
    }
    await runLogin(email, password);
  };

  return (
    <div className="flex min-h-[100vh] flex-col items-center justify-center bg-muted p-6 md:p-10">
      <div className="w-full max-w-sm md:max-w-5xl">
        <div className="flex flex-col gap-4">
          <Card className="w-full overflow-hidden rounded-lg border p-0 shadow-sm">
            <CardContent className="grid grid-cols-1 p-0 md:grid-cols-2">
              <form onSubmit={onSubmit} className="p-6 md:p-8 lg:p-10">
                <FieldGroup className="gap-4">
                  <div className="flex flex-col items-center justify-center gap-4 text-center">
                    <TypographyH2 className="text-2xl font-bold text-secondary sm:text-xl md:text-3xl lg:text-3xl">
                      Đăng nhập hệ thống
                    </TypographyH2>
                    <div className="flex flex-col items-center gap-1">
                      <PointerHighlight>
                        <p className="relative z-10 text-lg font-bold uppercase tracking-tight text-primary sm:text-sm md:text-xl xl:text-2xl">
                          Hệ thống Kết nối Phụ huynh
                        </p>
                      </PointerHighlight>
                      <p className="text-sm font-medium italic text-muted-foreground md:text-base">
                        &quot;Tâm an lòng, con vững bước - Đồng hành cùng tương lai
                        con tại HUB&quot;
                      </p>
                    </div>
                  </div>

                  <Field>
                    {isDevelopment ? (
                      <>
                        <FieldLabel className="font-medium text-primary">
                          Tài khoản development
                        </FieldLabel>
                        <Select
                          value={selectedDevLoginId}
                          onValueChange={onSelectDevLogin}
                          disabled={busy || devLoginOptionsLoading}
                        >
                          <SelectTrigger className="h-11 w-full rounded-lg">
                            <SelectValue
                              placeholder={
                                devLoginOptionsLoading
                                  ? "Đang tải user từ database..."
                                  : "Chọn tài khoản có sẵn trong database"
                              }
                            />
                          </SelectTrigger>
                          <SelectContent>
                            {devLoginOptions.map((option) => (
                              <SelectItem key={option.id} value={option.id}>
                                {option.name?.trim() || option.email}
                                <span className="text-xs text-muted-foreground">
                                  {option.email} | {option.description}
                                </span>
                              </SelectItem>
                            ))}
                          </SelectContent>
                        </Select>
                        <FieldDescription>
                          Danh sách chỉ hiện ở môi trường development. Khi chọn sẽ
                          đăng nhập trực tiếp theo user trong database, không cần
                          điều chỉnh hay biết mật khẩu.
                        </FieldDescription>
                      </>
                    ) : null}
                  </Field>

                  <Field>
                    <FieldLabel htmlFor="email" className="font-medium text-primary">
                      Email
                    </FieldLabel>
                    <Input
                      id="email"
                      type="email"
                      autoComplete="username"
                      value={email}
                      onChange={(event) => {
                        if (selectedDevLoginId) {
                          setSelectedDevLoginId("");
                        }
                        setEmail(event.target.value);
                      }}
                      required
                      disabled={busy}
                      placeholder="example@email.com"
                    />
                  </Field>

                  <Field>
                    <div className="flex items-center justify-between">
                      <FieldLabel htmlFor="password" className="font-medium text-primary">
                        Mật khẩu
                      </FieldLabel>
                      <Link
                        href={AUTH_REGISTER_PATH}
                        className="text-sm font-medium text-primary transition-colors hover:text-primary/80"
                      >
                        Quên mật khẩu?
                      </Link>
                    </div>
                    <div className="relative">
                      <Input
                        id="password"
                        type={showPassword ? "text" : "password"}
                        autoComplete="current-password"
                        value={password}
                        onChange={(event) => {
                          if (selectedDevLoginId) {
                            setSelectedDevLoginId("");
                          }
                          setPassword(event.target.value);
                        }}
                        required={!isDevelopment || !selectedDevLoginId}
                        disabled={busy || (isDevelopment && !!selectedDevLoginId)}
                        placeholder={
                          isDevelopment && selectedDevLoginId
                            ? "Đã bỏ qua mật khẩu cho tài khoản development đã chọn"
                            : "Nhập mật khẩu của bạn"
                        }
                        className="pr-10"
                      />
                      <Button
                        type="button"
                        variant="ghost"
                        className="absolute right-0 top-0 h-full px-3 py-2 hover:bg-transparent"
                        onClick={() => setShowPassword((value) => !value)}
                        disabled={busy}
                      >
                        {showPassword ? (
                          <EyeOff className="h-4 w-4 text-muted-foreground" />
                        ) : (
                          <Eye className="h-4 w-4 text-muted-foreground" />
                        )}
                      </Button>
                    </div>
                  </Field>

                  <Field>
                    <Button
                      type="submit"
                      className="min-h-[44px] w-full bg-destructive px-8 text-destructive-foreground hover:bg-destructive/90"
                      disabled={busy}
                    >
                      <span className="text-base font-bold">
                        {busy
                          ? isDevelopment && selectedDevLoginId
                            ? "Đang đăng nhập development..."
                            : "Đang đăng nhập..."
                          : "Đăng nhập"}
                      </span>
                    </Button>
                  </Field>

                  <FieldSeparator className="*:data-[slot=field-separator-content]:bg-card">
                    Hoặc tiếp tục với
                  </FieldSeparator>

                  <Field>
                    <Button
                      type="button"
                      variant="outline"
                      className="min-h-[44px] w-full border-secondary/30 hover:bg-secondary/10"
                      onClick={() =>
                        toast.info("Đăng nhập Google cho cổng quản trị chưa được cấu hình.")
                      }
                    >
                      <span className="text-xl font-bold text-secondary">G</span>
                      <span className="text-base font-bold text-secondary">
                        Đăng nhập bằng Google
                      </span>
                    </Button>
                  </Field>

                  <FieldError>{error}</FieldError>

                  <FieldDescription className="text-center text-sm md:text-base">
                    Nếu bạn chưa có tài khoản?{" "}
                    <Link
                      href={AUTH_REGISTER_PATH}
                      className="font-bold text-primary transition-colors hover:text-primary/80"
                    >
                      Đăng ký
                    </Link>
                  </FieldDescription>
                </FieldGroup>
              </form>

              <div className="relative hidden bg-muted text-foreground md:flex">
                <img
                  src="https://hub.edu.vn/DATA/IMAGES/2024/12/31/20241231235033-1vehub.jpg"
                  alt="Hình ảnh HUB"
                  title="Hình ảnh HUB"
                  loading="eager"
                  className="absolute inset-0 h-full w-full object-cover"
                />
              </div>
            </CardContent>
          </Card>
        </div>
      </div>
    </div>
  );
}

src/hooks/queries.ts.content:
"use client";

import {
  useMutation,
  useQuery,
  useQueryClient,
  type UseMutationResult,
  type UseQueryResult,
} from "@tanstack/react-query";
import {
  api,
  type Category,
  type CategoryUsage,
  type ChangePasswordInput,
  type CreateCategoryInput,
  type CreateUserInput,
  type RbacPermission,
  type RbacRole,
  type UpdateCategoryInput,
  type UpdateProfileInput,
  type UpdateUserInput,
  type User,
} from "@/lib/api";

export const queryKeys = {
  categories: () => ["categories"] as const,
  categoriesTrashed: () => ["categories", "trashed"] as const,
  categoryUsage: () => ["categories", "usage"] as const,
  staffProfile: (id: string | number) => ["users", "staff-profile", id] as const,
  staffUserList: () => ["users", "staff-list"] as const,
  usersTrashed: () => ["users", "trashed"] as const,
  rbacCatalog: () => ["rbac", "catalog"] as const,
};

export type CategoriesListData = { items: Category[]; total: number };
export type UsersListData = { items: User[]; total: number };
export type RbacCatalog = { permissions: RbacPermission[]; roles: RbacRole[] };

export const useCategories = (opts?: { enabled?: boolean }) =>
  useQuery<Category[], Error>({
    queryKey: queryKeys.categories(),
    queryFn: async () => {
      const res = await api.categories.list();
      return Array.isArray(res) ? res : res.items;
    },
    enabled: opts?.enabled ?? true,
  });

export const useCategoriesAdmin = (opts?: {
  enabled?: boolean;
  listParams?: { q?: string; page?: number; limit?: number; activeOnly?: boolean };
}): UseQueryResult<CategoriesListData, Error> =>
  useQuery({
    queryKey: [...queryKeys.categories(), "admin", opts?.listParams ?? null] as const,
    queryFn: async () => {
      const res = await api.categories.list({
        q: opts?.listParams?.q,
        page: opts?.listParams?.page,
        limit: opts?.listParams?.limit,
        activeOnly: opts?.listParams?.activeOnly,
      });
      if (Array.isArray(res)) {
        return { items: res, total: res.length };
      }
      return { items: res.items, total: res.total };
    },
    enabled: opts?.enabled ?? true,
  });

export const useTrashedCategories = (opts?: {
  enabled?: boolean;
  listParams?: { page?: number; limit?: number; q?: string };
}): UseQueryResult<CategoriesListData, Error> =>
  useQuery({
    queryKey: [...queryKeys.categoriesTrashed(), opts?.listParams ?? null] as const,
    queryFn: async () => {
      const lp = opts?.listParams;
      const res = await api.categories.listTrashed({
        page: lp?.page ?? 1,
        limit: lp?.limit ?? 15,
        q: lp?.q,
      });
      return { items: res.items, total: res.total };
    },
    enabled: opts?.enabled ?? true,
  });

export const useCategoryUsage = () =>
  useQuery<CategoryUsage[], Error>({
    queryKey: queryKeys.categoryUsage(),
    queryFn: () => api.categories.usage(),
  });

export const useCreateCategory = (): UseMutationResult<
  Category,
  Error,
  CreateCategoryInput
> => {
  const qc = useQueryClient();
  return useMutation({
    mutationFn: (input) => api.categories.create(input),
    onSuccess: () => {
      void qc.invalidateQueries({ queryKey: queryKeys.categories() });
      void qc.invalidateQueries({ queryKey: queryKeys.categoriesTrashed() });
      void qc.invalidateQueries({ queryKey: queryKeys.categoryUsage() });
    },
  });
};

export const useUpdateCategory = (): UseMutationResult<
  Category,
  Error,
  { id: string | number; input: UpdateCategoryInput }
> => {
  const qc = useQueryClient();
  return useMutation({
    mutationFn: ({ id, input }) => api.categories.update(id, input),
    onSuccess: () => {
      void qc.invalidateQueries({ queryKey: queryKeys.categories() });
      void qc.invalidateQueries({ queryKey: queryKeys.categoryUsage() });
    },
  });
};

export const useDeleteCategory = (): UseMutationResult<
  void,
  Error,
  string | number
> => {
  const qc = useQueryClient();
  return useMutation({
    mutationFn: (id) => api.categories.remove(id),
    onSuccess: () => {
      void qc.invalidateQueries({ queryKey: queryKeys.categories() });
      void qc.invalidateQueries({ queryKey: queryKeys.categoriesTrashed() });
      void qc.invalidateQueries({ queryKey: queryKeys.categoryUsage() });
    },
  });
};

export const useRestoreCategory = (): UseMutationResult<
  Category,
  Error,
  string | number
> => {
  const qc = useQueryClient();
  return useMutation({
    mutationFn: (id) => api.categories.restore(id),
    onSuccess: () => {
      void qc.invalidateQueries({ queryKey: queryKeys.categories() });
      void qc.invalidateQueries({ queryKey: queryKeys.categoriesTrashed() });
      void qc.invalidateQueries({ queryKey: queryKeys.categoryUsage() });
    },
  });
};

export const usePurgeTrashedCategory = (): UseMutationResult<
  void,
  Error,
  string | number
> => {
  const qc = useQueryClient();
  return useMutation({
    mutationFn: (id) => api.categories.purgeTrashed(id),
    onSuccess: () => {
      void qc.invalidateQueries({ queryKey: queryKeys.categories() });
      void qc.invalidateQueries({ queryKey: queryKeys.categoriesTrashed() });
      void qc.invalidateQueries({ queryKey: queryKeys.categoryUsage() });
    },
  });
};

export const useStaffProfile = (userId: string | number | null | undefined) =>
  useQuery<User, Error>({
    queryKey: queryKeys.staffProfile(userId ?? "missing"),
    queryFn: () => api.users.get(userId as string | number),
    enabled:
      (typeof userId === "string" && userId.trim().length > 0) ||
      (typeof userId === "number" && userId > 0),
  });

export const useUpdateStaffProfile = (): UseMutationResult<
  User,
  Error,
  { id: string | number; input: UpdateProfileInput }
> => {
  const qc = useQueryClient();
  return useMutation({
    mutationFn: ({ id, input }) => api.users.updateProfile(id, input),
    onSuccess: (u) => {
      qc.setQueryData(queryKeys.staffProfile(u.id), u);
    },
  });
};

export const useChangeStaffPassword = (): UseMutationResult<
  { ok: true },
  Error,
  { id: string | number; input: ChangePasswordInput }
> => {
  return useMutation({
    mutationFn: ({ id, input }) => api.users.changePassword(id, input),
  });
};

export const useRbacCatalog = (opts?: { enabled?: boolean }) =>
  useQuery<RbacCatalog, Error>({
    queryKey: queryKeys.rbacCatalog(),
    queryFn: async () => {
      const [permissions, roles] = await Promise.all([
        api.rbac.listPermissions(),
        api.rbac.listRoles(),
      ]);
      return { permissions, roles };
    },
    enabled: opts?.enabled ?? true,
  });

export const useStaffUserList = (opts?: {
  enabled?: boolean;
  listParams?: { q?: string; page?: number; limit?: number; filters?: Record<string, string> };
}): UseQueryResult<UsersListData, Error> =>
  useQuery({
    queryKey: [...queryKeys.staffUserList(), opts?.listParams ?? null] as const,
    queryFn: async () => {
      const res = await api.users.list({
        q: opts?.listParams?.q,
        page: opts?.listParams?.page,
        limit: opts?.listParams?.limit,
        filters: opts?.listParams?.filters,
      });
      return { items: res.items, total: res.total };
    },
    enabled: opts?.enabled ?? true,
  });

export const useTrashedStaffUsers = (opts?: {
  enabled?: boolean;
  listParams?: { page?: number; limit?: number; q?: string; filters?: Record<string, string> };
}): UseQueryResult<UsersListData, Error> =>
  useQuery({
    queryKey: [...queryKeys.usersTrashed(), opts?.listParams ?? null] as const,
    queryFn: async () => {
      const lp = opts?.listParams;
      const res = await api.users.listTrashed({
        page: lp?.page ?? 1,
        limit: lp?.limit ?? 25,
        q: lp?.q,
        filters: lp?.filters,
      });
      return { items: res.items, total: res.total };
    },
    enabled: opts?.enabled ?? true,
  });

export const useCreateStaffUser = (): UseMutationResult<
  User,
  Error,
  CreateUserInput
> => {
  const qc = useQueryClient();
  return useMutation({
    mutationFn: (input) => api.users.create(input),
    onSuccess: () => {
      void qc.invalidateQueries({ queryKey: queryKeys.staffUserList() });
      void qc.invalidateQueries({ queryKey: queryKeys.usersTrashed() });
    },
  });
};

export const useUpdateStaffUser = (): UseMutationResult<
  User,
  Error,
  { id: string | number; input: UpdateUserInput }
> => {
  const qc = useQueryClient();
  return useMutation({
    mutationFn: ({ id, input }) => api.users.update(id, input),
    onSuccess: (u) => {
      void qc.invalidateQueries({ queryKey: queryKeys.staffUserList() });
      void qc.invalidateQueries({ queryKey: queryKeys.usersTrashed() });
      qc.setQueryData(queryKeys.staffProfile(u.id), u);
    },
  });
};

export const useDeleteStaffUser = (): UseMutationResult<
  void,
  Error,
  string | number
> => {
  const qc = useQueryClient();
  return useMutation({
    mutationFn: (id) => api.users.remove(id),
    onSuccess: (_, id) => {
      void qc.invalidateQueries({ queryKey: queryKeys.staffUserList() });
      void qc.invalidateQueries({ queryKey: queryKeys.usersTrashed() });
      qc.removeQueries({ queryKey: queryKeys.staffProfile(id) });
    },
  });
};

export const useRestoreStaffUser = (): UseMutationResult<
  User,
  Error,
  string | number
> => {
  const qc = useQueryClient();
  return useMutation({
    mutationFn: (id) => api.users.restore(id),
    onSuccess: () => {
      void qc.invalidateQueries({ queryKey: queryKeys.staffUserList() });
      void qc.invalidateQueries({ queryKey: queryKeys.usersTrashed() });
    },
  });
};

export const usePurgeTrashedStaffUser = (): UseMutationResult<
  void,
  Error,
  string | number
> => {
  const qc = useQueryClient();
  return useMutation({
    mutationFn: (id) => api.users.purgeTrashed(id),
    onSuccess: (_, id) => {
      void qc.invalidateQueries({ queryKey: queryKeys.staffUserList() });
      void qc.invalidateQueries({ queryKey: queryKeys.usersTrashed() });
      qc.removeQueries({ queryKey: queryKeys.staffProfile(id) });
    },
  });
};

